function httpRequest(urlStr, method, body, apiKey) {
  return new Promise((resolve, reject) => {
    const isHttps = urlStr.startsWith('https://');
    const lib = isHttps ? require('https') : require('http');
    const noProto = urlStr.slice(isHttps ? 8 : 7);
    const slashAt = noProto.indexOf('/');
    const hostEnd = slashAt !== -1 ? slashAt : noProto.length;
    const hostPort = noProto.slice(0, hostEnd);
    const path = noProto.slice(hostEnd) || '/';
    const colonAt = hostPort.lastIndexOf(':');
    const hostname = colonAt !== -1 ? hostPort.slice(0, colonAt) : hostPort;
    const port = colonAt !== -1 ? Number(hostPort.slice(colonAt + 1)) : (isHttps ? 443 : 80);
    const bodyStr = JSON.stringify(body);
    const hdrs = { 'Content-Type': 'application/json', 'Content-Length': bodyStr.length };
    if (apiKey) hdrs['api-key'] = apiKey;
    const req = lib.request(
      { hostname, port, path, method, headers: hdrs },
      res => {
        let d = '';
        res.on('data', c => d += c);
        res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({}); } });
      }
    );
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

const GEMINI_API_KEY = $env.GEMINI_API_KEY || 'YOUR_GEMINI_API_KEY';
const QDRANT_URL = $env.QDRANT_URL || 'http://localhost:6333';
const QDRANT_API_KEY = $env.QDRANT_API_KEY || '';
const COLLECTION = $env.QDRANT_COLLECTION || 'test_bot_knowledge';

let userQuery = query.trim();
let chatId = '';
try {
  const parsed = JSON.parse(userQuery);
  userQuery = parsed.query || userQuery;
  chatId = parsed.chat_id || '';
} catch(e) {}

if (!userQuery) return 'No query provided.';

const embedData = await httpRequest(
  `https://generativelanguage.googleapis.com/v1beta/models/gemini-embedding-001:embedContent?key=${GEMINI_API_KEY}`,
  'POST',
  { model: 'models/gemini-embedding-001', content: { parts: [{ text: userQuery }] } }
);
const vector = embedData.embedding?.values || [];
if (vector.length === 0) return 'Failed to embed query. Response: ' + JSON.stringify(embedData).slice(0, 200);

const searchBody = { vector, limit: 5, with_payload: true, score_threshold: 0.3 };
if (chatId) {
  searchBody.filter = { must: [{ key: 'chat_id', match: { value: chatId } }] };
}
const searchData = await httpRequest(`${QDRANT_URL}/collections/${COLLECTION}/points/search`, 'POST', searchBody, QDRANT_API_KEY);
const results = searchData.result || [];

if (results.length === 0) return 'No relevant content found. Ask the user to name the document or upload it first.';

return results.map(r => `[Source: ${r.payload?.document_name || 'Unknown'}]\n${r.payload?.content || ''}`).join('\n\n---\n\n');

