const QDRANT_URL = $env.QDRANT_URL || 'http://localhost:6333';
const QDRANT_API_KEY = $env.QDRANT_API_KEY || '';
const COLLECTION = $env.QDRANT_COLLECTION || 'test_bot_knowledge';

const chatId = query.trim();
try {
  const data = await httpRequest(
    `${QDRANT_URL}/collections/${COLLECTION}/points/scroll`,
    'POST',
    {
      filter: { must: [{ key: 'chat_id', match: { value: chatId } }] },
      limit: 100,
      with_payload: ['document_name', 'doc_type'],
      with_vector: false
    },
    QDRANT_API_KEY
  );
  const results = data.result?.points || data.result || [];
  const seen = new Set();
  const docs = [];
  for (const r of results) {
    const name = r.payload?.document_name || 'Unnamed';
    const type = r.payload?.doc_type || '?';
    if (!seen.has(name)) { seen.add(name); docs.push(name + ' [' + type + ']'); }
  }
  if (docs.length === 0) return 'No documents indexed yet for this session.';
  return 'Indexed documents (' + docs.length + '): ' + docs.join(', ');
} catch(e) { return 'Error: ' + e.message; }

