const QDRANT_URL = $env.QDRANT_URL || 'http://localhost:6333';
const QDRANT_API_KEY = $env.QDRANT_API_KEY || '';
const COLLECTION = $env.QDRANT_COLLECTION || 'test_bot_knowledge';

let parsed;
try { parsed = JSON.parse(query); } catch(e) { return 'Invalid input. Expected JSON {chat_id, document_name}'; }
const chatId = parsed.chat_id || '';
const docName = parsed.document_name || '';
if (!chatId || !docName) return 'Missing chat_id or document_name.';
try {
  const data = await httpRequest(
    `${QDRANT_URL}/collections/${COLLECTION}/points/delete`,
    'POST',
    { filter: { must: [
      { key: 'chat_id', match: { value: chatId } },
      { key: 'document_name', match: { value: docName } }
    ] } },
    QDRANT_API_KEY
  );
  if (data.status === 'ok') return 'Deleted "' + docName + '" successfully.';
  return 'Result: ' + JSON.stringify(data.result || data);
} catch(e) { return 'Error: ' + e.message; }

const out = $input.first().json;
const prepIn = $('Prepare Chat Agent Input').first().json;
let response = out.output || out.text || 'Sorry, I could not generate a response.';
return [{ json: {
  session_id: prepIn.session_id,
  response,
  timestamp: new Date().toISOString()
} }];

const GEMINI_API_KEY = $env.GEMINI_API_KEY || 'AIzaSyDKJFfT7VcgjRcKwAPbSgWiOF-Ii88f3lw';
const QDRANT_URL = $env.QDRANT_URL || 'http://localhost:6333';
const QDRANT_API_KEY = $env.QDRANT_API_KEY || '';
const COLLECTION = $env.QDRANT_COLLECTION || 'test_bot_knowledge';

const raw = $input.first().json;
const body = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const session_id  = (body.session_id  || '').toString().trim();
const file_base64 = (body.file_base64 || '').toString().trim();
const mime_type   = (body.mime_type   || 'application/pdf').toString().trim();
const file_name   = (body.file_name   || 'document').toString().trim();

if (!session_id)  throw new Error('session_id is required');
if (!file_base64) throw new Error('file_base64 is required');

return [{ json: { session_id, file_base64, mime_type, file_name, GEMINI_API_KEY, QDRANT_URL, QDRANT_API_KEY, COLLECTION } }];

const res = $input.first().json;
const uploadIn = $('Validate Upload Input').first().json;

const mimeToType = {
  'application/pdf': 'PDF',
  'text/plain': 'TXT',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document': 'DOCX',
  'application/msword': 'DOC',
  'application/vnd.openxmlformats-officedocument.presentationml.presentation': 'PPTX',
  'application/vnd.ms-powerpoint': 'PPT'
};

const mimeType = uploadIn.mime_type || 'application/octet-stream';
const docType  = mimeToType[mimeType] || mimeType.split('/').pop().toUpperCase();
const fileName = uploadIn.file_name || 'document';
const docName  = fileName.replace(/\.[^.]+$/, '');

let content = '';
try { content = res.candidates?.[0]?.content?.parts?.[0]?.text || ''; } catch(e) {}
if (!content || content.length < 10) content = 'Document: ' + fileName;

return [{ json: {
  pageContent: content.substring(0, 50000),
  metadata: {
    chat_id:           uploadIn.session_id,
    document_name:     docName,
    original_filename: fileName,
    doc_type:          docType,
    mime_type:         mimeType,
    timestamp:         new Date().toISOString()
  },
  chat_id:         uploadIn.session_id,
  document_name:   docName,
  doc_type:        docType,
  GEMINI_API_KEY:  uploadIn.GEMINI_API_KEY
} }];

const item = $input.first().json;
const pageContent   = item.pageContent || '';
const chat_id       = item.chat_id || item.metadata?.chat_id || '';
const document_name = item.document_name || item.metadata?.document_name || 'document';
const doc_type      = item.doc_type  || item.metadata?.doc_type  || 'TXT';
const mime_type         = item.metadata?.mime_type || '';
const original_filename = item.metadata?.original_filename || document_name;
const timestamp         = item.metadata?.timestamp || new Date().toISOString();
const GEMINI_API_KEY    = item.GEMINI_API_KEY || '';
const QDRANT_URL        = item.QDRANT_URL || $env.QDRANT_URL || 'http://localhost:6333';
const QDRANT_API_KEY    = item.QDRANT_API_KEY || $env.QDRANT_API_KEY || '';
const COLLECTION        = $env.QDRANT_COLLECTION || 'test_bot_knowledge';

const chunkSize = 1000, overlap = 100;
const chunks = [];
if (pageContent.length === 0) {
  chunks.push('(empty document)');
} else {
  let pos = 0;
  while (pos < pageContent.length) {
    chunks.push(pageContent.substring(pos, pos + chunkSize));
    pos += chunkSize - overlap;
    if (pos + overlap >= pageContent.length) {
      if (pos < pageContent.length) chunks.push(pageContent.substring(pos));
      break;
    }
  }
}

return chunks.map(chunk => ({ json: {
  chunk,
  chat_id, document_name, doc_type, mime_type, original_filename, timestamp,
  GEMINI_API_KEY, QDRANT_URL, COLLECTION
} }));

const embedding = $input.item.json;
const orig = $('Split Chunks').item.json;

const vector = embedding.embedding?.values || [];
if (vector.length === 0) return [];

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

return [{ json: {
  point: {
    id: uuid(),
    vector,
    payload: {
      content:           orig.chunk,
      chat_id:           orig.chat_id,
      document_name:     orig.document_name,
      doc_type:          orig.doc_type,
      mime_type:         orig.mime_type,
      original_filename: orig.original_filename,
      timestamp:         orig.timestamp
    }
  },
  chat_id:       orig.chat_id,
  document_name: orig.document_name,
  doc_type:      orig.doc_type,
  QDRANT_URL:    orig.QDRANT_URL,
  COLLECTION:    orig.COLLECTION
} }];

const items = $input.all();
if (items.length === 0) throw new Error('No embeddings generated');

const first  = items[0].json;
const points = items.map(i => i.json.point);

return [{ json: {
  points,
  chat_id:         first.chat_id,
  document_name:   first.document_name,
  doc_type:        first.doc_type,
  chunks_inserted: points.length,
  QDRANT_URL:      first.QDRANT_URL,
  COLLECTION:      first.COLLECTION
} }];

const aggrData = $('Aggregate Points').first().json;
return [{ json: {
  status:          'indexed',
  session_id:      aggrData.chat_id,
  document_name:   aggrData.document_name,
  doc_type:        aggrData.doc_type,
  chunks_inserted: aggrData.chunks_inserted,
  message:         'Successfully indexed "' + aggrData.document_name + '" (' + aggrData.doc_type + ') with ' + aggrData.chunks_inserted + ' chunks.',
  timestamp:       new Date().toISOString()
} }];
